  postprocessor.hashCode ^
  htmlOutput.hashCode ^
  extractionTimeoutSecs.hashCode ^
  maxConcurrentExtractions.hashCode ^
  resultFormat.hashCode ^
  securityLimits.hashCode ^
  maxEmbeddedFileBytes.hashCode ^
  outputFormat.hashCode ^
