    this.forceOcrPages,
    this.disableOcr,
    this.chunking,
    this.contentFilter,
    this.images,
    this.pdfOptions,
    this.tokenReduction,
    this.languageDetection,
    this.pages,
    this.keywords,
    this.postprocessor,
    this.htmlOutput,
    this.resultFormat,
    this.outputFormat,
    this.includeDocumentStructure,
    this.layout,
    this.transcription,
    this.timeoutSecs,
    this.treeSitter,
    this.structuredExtraction,
